// TaskLatestDuration returns the duration of the most recent completed/failed execution.
func TaskLatestDuration(executions []models.Execution) string {
	for i := len(executions) - 1; i >= 0; i-- {
		if executions[i].DurationMs > 0 {
			return formatDuration(executions[i].DurationMs)
		}
	}
	return ""
}

